// 1. Capture the raw input data blocks from the HTTP Request (GET) node
const itemData = $input.item.json;
const htmlText = itemData.data || ''; 
const headers = itemData.headers || {};

// 2. Extract CSRF Token safely
const tokenMatch = htmlText.match(/meta name=["']csrf-token["'] content=["']([^"']+)["']/);
const csrfToken = tokenMatch ? tokenMatch[1] : '';

// 3. Extract cookies cleanly to bypass 419 validation blocks
const cookieHeader = headers['set-cookie'] || [];
const cookieString = Array.isArray(cookieHeader) 
  ? cookieHeader.map(c => c.split(';')[0]).join('; ')
  : typeof cookieHeader === 'string' ? cookieHeader.split(';')[0] : '';

/* 4. FIXED DYNAMIC LINKING: 
   Reach back directly to the 'Loop Over Items' node configuration 
   instead of reading the immediate HTTP GET response.
   ⚠️ Make sure the name inside quotes matches your loop node exactly!
*/
const loopContext = $("Loop Over Items").item.json; 

// 5. Return the payload built perfectly for your HTTP Request1 (POST) node
return {
  slug: loopContext.slug,
  name: loopContext.name,
  csrfToken: csrfToken.trim(),
  cookieString: cookieString,
  clause: loopContext.clause
};

