// 1. Fetch the stored briefing report lines out of workflow memory
const storage = $getWorkflowStaticData('global');
const reportArray = storage.reportLines || [];

// 2. Clear out the storage memory so it starts fresh 
storage.reportLines = [];

// 3. Return the single consolidated text block to Telegram
return {
  combinedReport: "📊 *DAILY MARKET SCREENER BRIEFING*\n\n" + (reportArray.join('') || "_Testing storage reset. Run full workflow now._")
};

// 1. FIXED SYNTAX: Grab the scanner name using the clean property accessor method
const scanName = $("Loop Over Items").item.json.name || "Unknown Scanner";
const responseData = $input.item.json.data || '';

let stockData = [];
try {
  const parsedBody = typeof responseData === 'string' ? JSON.parse(responseData) : responseData;
  stockData = parsedBody.data || [];
} catch (e) {
  stockData = [];
}

// 2. Format the lines for this specific scan run
let lineText = "";
if (stockData.length > 0) {
  lineText += `✅ *${scanName}*\n`;
  const stockRows = stockData.map(stock => `• \`${stock.nsecode}\` - ${stock.name}`).join('\n');
  lineText += stockRows + '\n\n';
} else {
  lineText += `❌ *${scanName}*\n_No stocks matched criteria today._\n\n`;
}

// 3. Save this text inside n8n's long-term workflow storage memory
const storage = $getWorkflowStaticData('global');
if (!storage.reportLines) {
  storage.reportLines = [];
}
storage.reportLines.push(lineText);

// 4. Pass the item right back to the loop unaltered
return $input.all();
